def ingest_data(meta):
    # Define the URL for the external data source
    data_url = "https://raw.githubusercontent.com/Cyoda-platform/cyoda-ai/refs/heads/ai-2.x/data/test-inputs/v1/connections/london_houses.csv"

    try:
